+    emit_mount_banner(&open_fs, mountpoint, rw);
+    emit_optional_recovery_banner(&open_fs);
+
+    if rw {
+        open_fs
+            .enable_writes(&cx)
+            .context("failed to enable write support")?;
+    }
+    mount_with_fuse(open_fs, mountpoint, rw, allow_other, auto_unmount)?;

     info!(
